mapper.select:
SELECT COUNT(*)
FROM favorite_transfers
WHERE user_id = #{userId}
  AND transfer_id = #{transferId}

mapper.delete:
DELETE FROM favorite_transfers
WHERE user_id = #{userId}
  AND transfer_id = #{transferId}

mapper.select:
SELECT transfer_id
FROM favorite_transfers
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}
